<template><div class="mgr"><h2>🥊 竞争对手</h2><el-button type="primary" size="small" @click="show=true;reset()">+ 添加竞品</el-button><el-table :data="list" stripe size="small" style="margin-top:8px"><el-table-column prop="name" label="名称"/><el-table-column prop="industry" label="行业"/><el-table-column prop="strengths" label="优势" min-width="140"/><el-table-column prop="weaknesses" label="劣势" min-width="140"/><el-table-column label="威胁"><template #default="{row}"><el-tag :type="row.threat_level==='高'?'danger':'warning'" size="small">{{ row.threat_level }}</el-tag></template></el-table-column></el-table><el-dialog v-model="show" title="添加竞品"><el-form label-width="60px"><el-form-item label="名称"><el-input v-model="f.name"/></el-form-item><el-form-item label="行业"><el-input v-model="f.industry"/></el-form-item><el-form-item label="优势"><el-input v-model="f.strengths"/></el-form-item><el-form-item label="劣势"><el-input v-model="f.weaknesses"/></el-form-item><el-form-item label="威胁"><el-select v-model="f.threatLevel" style="width:100%"><el-option label="高" value="高"/><el-option label="中" value="中"/><el-option label="低" value="低"/></el-select></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import {ref,reactive,onMounted} from 'vue';import request from '@/utils/request';import {ElMessage} from 'element-plus';const list=ref([]);const show=ref(false);const f=reactive({name:'',industry:'',strengths:'',weaknesses:'',threatLevel:'中'});function reset(){Object.assign(f,{name:'',industry:'',strengths:'',weaknesses:'',threatLevel:'中'})}async function fetch(){try{list.value=await request.get('/competitors')||[]}catch{}}async function save(){try{await request.post('/competitors',f);show.value=false;fetch();ElMessage.success('已添加')}catch{}}onMounted(fetch)</script>
<style scoped>.mgr{padding:0}</style>
